<style lang="scss">
	.hide {
		&--slide-in {
			transform: translateX(-100%);
			opacity: 0;
			filter: blur(5px);
			transition: all 0.8s;
		}
		&--underline {
			position: relative;
			width: fit-content;
			&::before {
				position: absolute;
				bottom: -8px;
				left: 0;
				opacity: 0;
				transition: all 0.3s;
				border-radius: 4px;
				width: 0%;
				height: 4px;
				content: '';
			}
		}
	}

	.show {
		&--slide-in {
			transform: translateX(0);
			opacity: 1;
			filter: blur(0);
		}
		&--underline::before {
			opacity: 1 !important;
			transition-delay: 500ms;
			width: 100% !important;
		}
	}

	.tooltable table > tbody > tr > td:nth-child(2) {
		display: flex;
		flex-direction: row;
		justify-content: end;
		gap: 1rem;
	}
	.scroll-content-primary {
		animation: slide 40s linear infinite; /* Horizontal scrolling effect */
	}
	.scroll-content-secondary {
		animation: slide-2 40s linear infinite;
	}
	.scroll-content-primary > li {
		text-align: center;
	}
	.scroll-content-secondary > li {
		text-align: center;
	}

	@keyframes primary {
		from {
			left: 0%;
		}
		to {
			left: -100%;
		}
	}
	@keyframes secondary {
		from {
			left: 100%;
		}
		to {
			left: 0%;
		}
	}
	@keyframes slide {
		from {
			transform: translateX(0);
		}
		to {
			transform: translateX(-100%);
		}
	}
	@keyframes slide-2 {
		from {
			transform: translateX(100%);
		}
		to {
			transform: translateX(0%);
		}
	}
	@media (prefers-reduced-motion: reduce) {
		.logos-ticker-container {
			animation-play-state: paused;
		}
	}
</style>
